class ILPAnalyzer:
    def __init__(self):
        self.latencies = {'ADD': 1, 'SUB': 1, 'MUL': 4, 'DIV': 8, 'LOAD': 3}

    def find_dependencies(self, instructions):
        deps = {'RAW': [], 'WAR': [], 'WAW': []}
        for i in range(len(instructions)):
            op_i, dest_i, src1_i, src2_i = instructions[i]
            for j in range(i + 1, len(instructions)):
                op_j, dest_j, src1_j, src2_j = instructions[j]
                # RAW: j reads what i writes
                if dest_i in (src1_j, src2_j):
                    deps['RAW'].append((i, j))
                # WAR: j writes what i reads
                if dest_j in (src1_i, src2_i):
                    deps['WAR'].append((i, j))
                # WAW: j writes what i writes
                if dest_i == dest_j:
                    deps['WAW'].append((i, j))
        return deps

    def critical_path_length(self, instructions):
        n = len(instructions)
        deps = self.find_dependencies(instructions)

        # Build adjacency list for RAW dependencies only
        # Edge weight = latency of the source instruction
        adj = {i: [] for i in range(n)}
        for (i, j) in deps['RAW']:
            latency = self.latencies[instructions[i][0]]
            adj[i].append((j, latency))

        # Longest path using dynamic programming (DAG, topological order = program order)
        # dist[i] = longest path ending at instruction i (inclusive of i's latency)
        dist = [0] * n
        parent = [-1] * n
        for i in range(n):
            # Base: instruction's own latency
            dist[i] = max(dist[i], self.latencies[instructions[i][0]])

        for i in range(n):
            for (j, latency) in adj[i]:
                new_dist = dist[i] + self.latencies[instructions[j][0]]
                if new_dist > dist[j]:
                    dist[j] = new_dist
                    parent[j] = i

        # Find the instruction with the longest path
        max_len = max(dist)
        end_node = dist.index(max_len)

        # Trace back the critical path
        path = []
        node = end_node
        while node != -1:
            path.append(node)
            node = parent[node]
        path.reverse()

        return max_len, path

    def theoretical_max_ipc(self, instructions):
        cp_length, _ = self.critical_path_length(instructions)
        return len(instructions) / cp_length

    def resource_constrained_schedule(self, instructions, resources):
        n = len(instructions)
        deps = self.find_dependencies(instructions)

        # For each instruction, find its RAW predecessors and the cycle they must complete by
        raw_preds = {i: [] for i in range(n)}
        for (src, dst) in deps['RAW']:
            raw_preds[dst].append(src)

        # Map operation to resource type (ADD and SUB share ALU)
        def resource_type(op):
            if op in ('ADD', 'SUB'):
                return 'ALU'
            return op

        # Resource capacity
        capacity = {}
        capacity['ALU'] = resources.get('ADD', 2)  # ADD and SUB share
        capacity['MUL'] = resources.get('MUL', 1)
        capacity['DIV'] = resources.get('DIV', 1)
        capacity['LOAD'] = resources.get('LOAD', 1)

        # Schedule greedily
        start_cycle = [None] * n
        end_cycle = [None] * n
        # Track resource usage per cycle: {cycle: {resource_type: count}}
        usage = {}

        scheduled = set()
        schedule = []

        cycle = 1
        while len(scheduled) < n:
            # Find ready instructions (all RAW preds completed)
            ready = []
            for i in range(n):
                if i in scheduled:
                    continue
                if all(end_cycle[p] is not None and end_cycle[p] < cycle for p in raw_preds[i]):
                    ready.append(i)

            # Try to schedule ready instructions
            for i in ready:
                op = instructions[i][0]
                rt = resource_type(op)
                lat = self.latencies[op]

                # Check resource availability for all cycles this instruction occupies
                can_schedule = True
                for c in range(cycle, cycle + lat):
                    if c not in usage:
                        usage[c] = {}
                    current = usage[c].get(rt, 0)
                    if current >= capacity[rt]:
                        can_schedule = False
                        break

                if can_schedule:
                    start_cycle[i] = cycle
                    end_cycle[i] = cycle + lat - 1
                    for c in range(cycle, cycle + lat):
                        if c not in usage:
                            usage[c] = {}
                        usage[c][rt] = usage[c].get(rt, 0) + 1
                    scheduled.add(i)
                    schedule.append((i, cycle))

            cycle += 1
            if cycle > 500:
                break

        total_cycles = max(end_cycle)
        ipc = n / total_cycles
        schedule.sort(key=lambda x: x[1])

        return total_cycles, ipc, schedule


# Test program
instructions = [
    ('MUL', 'R1', 'R2', 'R3'),
    ('ADD', 'R4', 'R1', 'R5'),
    ('ADD', 'R6', 'R7', 'R8'),
    ('MUL', 'R9', 'R6', 'R10'),
    ('SUB', 'R11', 'R4', 'R9'),
    ('ADD', 'R12', 'R11', 'R6'),
    ('LOAD', 'R13', 'R0', 'R0'),
    ('ADD', 'R14', 'R13', 'R12'),
]

analyzer = ILPAnalyzer()

deps = analyzer.find_dependencies(instructions)
print("Dependencies:")
for dep_type, pairs in deps.items():
    print(f"  {dep_type}: {pairs}")

cp_length, cp_instrs = analyzer.critical_path_length(instructions)
print(f"\nCritical path length: {cp_length} cycles")
print(f"Critical path instructions: {cp_instrs}")
print(f"Theoretical max IPC: {analyzer.theoretical_max_ipc(instructions):.2f}")

resources = {'ADD': 2, 'SUB': 2, 'MUL': 1, 'DIV': 1, 'LOAD': 1}
total_cycles, ipc, schedule = analyzer.resource_constrained_schedule(instructions, resources)
print(f"\nResource-constrained: {total_cycles} cycles, IPC = {ipc:.2f}")
print(f"Schedule: {schedule}")
